// Informações de um aluno na escola
let nomeAluno: string = "Mariana";
let serie: number = 7;
let aprovada: boolean = true;

console.log(nomeAluno); // Mariana
console.log(serie);     // 7
console.log(aprovada);  // true

// A temperatura pode mudar ao longo do dia
let temperatura: number = 18;
console.log(temperatura); // 18

temperatura = 25;
console.log(temperatura); // 25

temperatura = temperatura + 3;
console.log(temperatura); // 28

// Dados de um livro que você está lendo
let titulo: string = "O Hobbit";
let paginas: number = 310;
let terminouDeLer: boolean = false;

console.log(titulo);         // O Hobbit
console.log(paginas);        // 310
console.log(terminouDeLer);  // false

// Calculando o preço total de uma compra
let precoPorUnidade: number = 4;
let quantidade: number = 6;
let total: number = precoPorUnidade * quantidade;

console.log(total); // 24

// Descobrindo a idade de alguém
let anoAtual: number = 2026;
let anoNascimento: number = 2014;
let idade: number = anoAtual - anoNascimento;

console.log(idade); // 12

// Uma variável de texto pode ser atualizada
let status: string = "estudando";
console.log(status); // estudando

status = "jogando";
console.log(status); // jogando

// Dados de um perfil de rede social
const nomeUsuario: string = "@maria_dev";
let seguidores: number = 230;
let bio: string = "Aprendendo a programar!";

console.log(nomeUsuario); // @maria_dev

seguidores = seguidores + 1;
console.log(seguidores); // 231

bio = "Estudante de TypeScript";
console.log(bio); // Estudante de TypeScript

// nomeUsuario = "@outra"; // ERRO! const não permite

// Constantes de uma receita
const TEMPERATURA_FORNO: number = 180;
const TEMPO_MINUTOS: number = 40;
let porcoes: number = 8;

console.log(TEMPERATURA_FORNO); // 180
console.log(TEMPO_MINUTOS);     // 40
console.log(porcoes);           // 8

porcoes = 12;
console.log(porcoes); // 12

// Controle de notas na escola
const NOTA_MAXIMA: number = 10;
let notaAtual: number = 7;

console.log(notaAtual);   // 7
console.log(NOTA_MAXIMA); // 10

notaAtual = 9;
console.log(notaAtual); // 9

// Simulando o clima ao longo do dia
const CIDADE: string = "Curitiba";
let temperatura: number = 14;
let estaChovendo: boolean = true;

console.log(CIDADE);        // Curitiba
console.log(temperatura);   // 14
console.log(estaChovendo);  // true

temperatura = 22;
estaChovendo = false;
console.log(temperatura);   // 22
console.log(estaChovendo);  // false

// Placar de um jogo de tabuleiro
const JOGADOR_1: string = "Ana";
const JOGADOR_2: string = "Bruno";
let pontosAna: number = 0;
let pontosBruno: number = 0;

pontosAna = pontosAna + 5;
pontosBruno = pontosBruno + 3;

console.log(JOGADOR_1);  // Ana
console.log(pontosAna);  // 5
console.log(JOGADOR_2);  // Bruno
console.log(pontosBruno); // 3

// Quando usar const: valores que não mudam
const ANO_NASCIMENTO: number = 2014;
const NOME: string = "Lucas";

// Quando usar let: valores que mudam
let idade: number = 12;
let serie: number = 7;

console.log(NOME);           // Lucas
console.log(ANO_NASCIMENTO); // 2014
console.log(idade);          // 12

idade = 13;
serie = 8;
console.log(idade); // 13
console.log(serie); // 8

// Bons nomes: descrevem o que a variável guarda
let nomeDoAluno: string = "Beatriz";
let idadeEmAnos: number = 12;
let estaMatriculada: boolean = true;

console.log(nomeDoAluno);     // Beatriz
console.log(idadeEmAnos);     // 12
console.log(estaMatriculada); // true

// Nomes ruins vs nomes bons
// ❌ let t: number = 32;         // t de quê?
// ❌ let str: string = "Sol";    // abreviação vaga
// ❌ let flag: boolean = true;   // flag de quê?

// ✅ Versões claras:
let temperaturaGraus: number = 32;
let condicaoClima: string = "Sol";
let estaChovendo: boolean = false;

console.log(temperaturaGraus); // 32
console.log(condicaoClima);    // Sol
console.log(estaChovendo);     // false

// camelCase: a primeira palavra é minúscula,
// cada palavra seguinte começa com maiúscula
let corFavorita: string = "azul";
let numeroDaCasa: number = 42;
let temIrmaoMaisVelho: boolean = false;

console.log(corFavorita);       // azul
console.log(numeroDaCasa);      // 42
console.log(temIrmaoMaisVelho); // false

// Dados de uma viagem
let cidadeDestino: string = "Gramado";
let distanciaKm: number = 120;
let precisaDePassaporte: boolean = false;
let duracaoEmDias: number = 5;

console.log(cidadeDestino);       // Gramado
console.log(distanciaKm);         // 120
console.log(precisaDePassaporte); // false
console.log(duracaoEmDias);       // 5

// Constantes usam MAIÚSCULAS_COM_UNDERLINE
const VELOCIDADE_DA_LUZ: number = 299792;
const DIAS_NA_SEMANA: number = 7;
const NOTA_DE_CORTE: number = 6;

let notaDoAluno: number = 8;

console.log(NOTA_DE_CORTE); // 6
console.log(notaDoAluno);   // 8

// Booleanos ficam claros com prefixos como
// "esta", "tem", "pode", "deve"
let estaLogado: boolean = true;
let temNotificacao: boolean = false;
let podeComentar: boolean = true;
let deveAtualizar: boolean = false;

console.log(estaLogado);      // true
console.log(temNotificacao);  // false
console.log(podeComentar);    // true
console.log(deveAtualizar);   // false

// Criando e mostrando uma variável numérica
let altura: number = 155;
console.log(altura); // 155

// Criando e mostrando uma variável de texto
let cidade: string = "Porto Alegre";
console.log(cidade); // Porto Alegre

// Criando e mostrando um booleano
let gostaDePizza: boolean = true;
console.log(gostaDePizza); // true

// Três variáveis, três console.log
let materia: string = "Matemática";
let nota: number = 9;
let passou: boolean = true;

console.log(materia); // Matemática
console.log(nota);    // 9
console.log(passou);  // true

// Cuidado: "12" com aspas é string, não number!
let idadeTexto: string = "12";
let idadeNumero: number = 12;

console.log(idadeTexto);  // 12 (mas é texto!)
console.log(idadeNumero); // 12 (este é número)

// A ordem importa: primeiro declara, depois usa
let peso: number = 45;
console.log(peso); // 45

// Se inverter a ordem, dá erro:
// console.log(cor);  // ERRO: cor não existe ainda
// let cor = "azul";

// Perfil de um aluno na escola
let nomeAluno: string = "Beatriz";
let serie: number = 7;
let estaAprovada: boolean = true;

console.log(nomeAluno);    // Beatriz
console.log(serie);        // 7
console.log(estaAprovada); // true

// Dados de um pet
let nomePet: string = "Luna";
let pesoKg: number = 4;
let estaVacinada: boolean = true;

console.log(nomePet);      // Luna
console.log(pesoKg);       // 4
console.log(estaVacinada); // true

// Informações de um filme
let tituloFilme: string = "Interestelar";
let duracaoMinutos: number = 169;
let jaAssistiu: boolean = false;

console.log(tituloFilme);    // Interestelar
console.log(duracaoMinutos); // 169
console.log(jaAssistiu);     // false

// Dados de uma música na playlist
let nomeDaMusica: string = "Bohemian Rhapsody";
let duracaoSegundos: number = 355;
let eFavorita: boolean = true;

console.log(nomeDaMusica);    // Bohemian Rhapsody
console.log(duracaoSegundos); // 355
console.log(eFavorita);       // true

// Previsão do tempo
let cidade: string = "Florianópolis";
let temperaturaGraus: number = 27;
let estaChovendo: boolean = false;

console.log(cidade);            // Florianópolis
console.log(temperaturaGraus);  // 27
console.log(estaChovendo);      // false

// A ordem dos console.log importa!
let produto: string = "Caderno";
let preco: number = 15;
let temEstoque: boolean = true;

// A saída segue a ordem das chamadas:
console.log(produto);    // Caderno
console.log(preco);      // 15
console.log(temEstoque); // true

// Trocando notas entre dois alunos
let notaAna: number = 8;
let notaBruno: number = 6;

let temp: number = notaAna;
notaAna = notaBruno;
notaBruno = temp;

console.log(notaAna);   // 6
console.log(notaBruno); // 8

// Trocando nomes de cidades
let cidade1: string = "São Paulo";
let cidade2: string = "Curitiba";

let aux: string = cidade1;
cidade1 = cidade2;
cidade2 = aux;

console.log(cidade1); // Curitiba
console.log(cidade2); // São Paulo

// O que acontece SEM variável temporária (ERRADO)
let x: number = 100;
let y: number = 200;

x = y;
y = x;

console.log(x); // 200
console.log(y); // 200  ← os dois ficaram iguais!

// Trocando posições no ranking
let primeiro: string = "Maria";
let segundo: string = "João";

let reserva: string = primeiro;
primeiro = segundo;
segundo = reserva;

console.log(primeiro); // João
console.log(segundo);  // Maria

// Trocando temperaturas entre manhã e tarde
let manha: number = 15;
let tarde: number = 28;

let temporario: number = manha;
manha = tarde;
tarde = temporario;

console.log(manha); // 28
console.log(tarde); // 15

// O nome da variável auxiliar não importa,
// mas precisa ter o mesmo tipo
let pontosCasa: number = 3;
let pontosVisitante: number = 1;

let backup: number = pontosCasa;
pontosCasa = pontosVisitante;
pontosVisitante = backup;

console.log(pontosCasa);      // 1
console.log(pontosVisitante); // 3

// Revisão: let permite mudar, const não
let pontuacao: number = 0;
pontuacao = 10;
console.log(pontuacao); // 10

const LIMITE: number = 100;
// LIMITE = 200; // ERRO: const não pode ser reatribuído

// Revisão: camelCase em ação
let nomeCompleto: string = "Ana Clara";
let anoDeNascimento: number = 2014;
let estaEstudando: boolean = true;

console.log(nomeCompleto);     // Ana Clara
console.log(anoDeNascimento);  // 2014
console.log(estaEstudando);    // true

// Revisão: reatribuição com cálculo
let saldo: number = 100;
saldo = saldo + 50;
console.log(saldo); // 150

saldo = saldo - 30;
console.log(saldo); // 120

// Revisão: os três tipos básicos
let titulo: string = "O Pequeno Príncipe";
let paginas: number = 96;
let jaLeu: boolean = false;

console.log(titulo);  // O Pequeno Príncipe
console.log(paginas); // 96
console.log(jaLeu);   // false

// Revisão: var vs let vs const
// var idade = 12;    // funciona, mas evite — escopo confuso
let idade: number = 12;      // ✅ pode mudar
const NOME: string = "Lucas"; // ✅ nunca muda

idade = 13;
console.log(idade); // 13
console.log(NOME);  // Lucas

// Revisão: operações com variáveis numéricas
let temperatura: number = 20;
temperatura = temperatura + 5;
console.log(temperatura); // 25

temperatura = temperatura * 2;
console.log(temperatura); // 50
